// Testimonials.jsx — Auto-sliding Google-style reviews carousel
import { useEffect, useMemo, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import useScrollAnimation from '../hooks/useScrollAnimation';

const REVIEWS = [
  {
    id: 1,
    name: 'Olivia Tran',
    rating: 5,
    comment: 'Absolutely loved the coffee and brunch. The service felt warm and personal, and every dish was beautifully presented.',
    avatar: 'https://images.unsplash.com/photo-1494790108755-2616b612b3bc?w=120&q=80&auto=format',
  },
  {
    id: 2,
    name: 'Daniel Morris',
    rating: 5,
    comment: 'Caffe Sorella has the best flat white in the area. Friendly staff, quick service, and a very relaxing atmosphere.',
    avatar: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=120&q=80&auto=format',
  },
  {
    id: 3,
    name: 'Sofia Reed',
    rating: 5,
    comment: 'Our family breakfast here was fantastic. Fresh ingredients, generous portions, and amazing desserts.',
    avatar: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=120&q=80&auto=format',
  },
  {
    id: 4,
    name: 'Liam Parker',
    rating: 5,
    comment: 'Seafood platter and fish burger were both excellent. Great quality and consistency every visit.',
    avatar: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=120&q=80&auto=format',
  },
  {
    id: 5,
    name: 'Emma Collins',
    rating: 5,
    comment: 'The Turkish Delight Cheesecake and Lemon Meringue Pie were incredible. Easily one of my favorite cafe spots.',
    avatar: 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=120&q=80&auto=format',
  },
  {
    id: 6,
    name: 'Noah Bennett',
    rating: 5,
    comment: 'Great coffee, friendly team, and the vibe is premium without feeling pretentious. Highly recommend for brunch.',
    avatar: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=120&q=80&auto=format',
  },
];

function StarRating({ count }) {
  return (
    <div style={{ display: 'flex', gap: 4, marginBottom: 16 }}>
      {Array.from({ length: count }).map((_, i) => (
        <svg key={i} width="14" height="14" viewBox="0 0 24 24" fill="#c9a96e" aria-hidden="true">
          <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
        </svg>
      ))}
    </div>
  );
}

export default function Testimonials() {
  const [current, setCurrent] = useState(0);
  const [direction, setDirection] = useState(1);
  const [cardsPerView, setCardsPerView] = useState(1);
  const [paused, setPaused] = useState(false);
  const [touchStartX, setTouchStartX] = useState(0);
  const [sectionRef, inView] = useScrollAnimation(0.1);

  useEffect(() => {
    const updateCardsPerView = () => {
      if (window.innerWidth < 768) setCardsPerView(1);
      else if (window.innerWidth < 1100) setCardsPerView(2);
      else setCardsPerView(3);
    };

    updateCardsPerView();
    window.addEventListener('resize', updateCardsPerView);
    return () => window.removeEventListener('resize', updateCardsPerView);
  }, []);

  const goTo = (index, dir) => {
    setDirection(dir);
    setCurrent((index + REVIEWS.length) % REVIEWS.length);
  };

  const prev = () => goTo(current - 1, -1);
  const next = () => goTo(current + 1, 1);

  // Build visible cards from the current index with circular wrapping.
  const visibleReviews = useMemo(
    () => Array.from({ length: cardsPerView }, (_, i) => REVIEWS[(current + i) % REVIEWS.length]),
    [current, cardsPerView]
  );

  // Auto-slide every 4 seconds, and pause when hovered/touched.
  useEffect(() => {
    if (!inView || paused) return undefined;
    const timer = setInterval(() => {
      setDirection(1);
      setCurrent(prevIndex => (prevIndex + 1) % REVIEWS.length);
    }, 4000);

    return () => clearInterval(timer);
  }, [inView, paused]);

  const trackVariants = {
    enter: (dir) => ({ opacity: 0, x: dir > 0 ? 56 : -56 }),
    center: {
      opacity: 1,
      x: 0,
      transition: { staggerChildren: 0.08, delayChildren: 0.05 },
    },
    exit: (dir) => ({ opacity: 0, x: dir > 0 ? -56 : 56 }),
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 18, scale: 0.98 },
    visible: { opacity: 1, y: 0, scale: 1, transition: { duration: 0.45, ease: [0.22, 1, 0.36, 1] } },
  };

  const onTouchEnd = (endX) => {
    const delta = endX - touchStartX;
    if (Math.abs(delta) < 40) return;
    if (delta < 0) next();
    else prev();
  };

  return (
    <section id="testimonials" style={{ background: '#0f0a07', padding: 'clamp(80px,10vw,140px) clamp(24px,6vw,80px)', position: 'relative', overflow: 'hidden' }}>
      {/* Large decorative quote mark */}
      <div style={{
        position: 'absolute', top: '10%', left: '5%',
        fontFamily: "'Cormorant Garamond', serif",
        fontSize: 'clamp(120px,20vw,280px)', fontWeight: 300,
        color: 'rgba(201,169,110,0.04)', lineHeight: 1, userSelect: 'none',
        pointerEvents: 'none',
      }}>
        "
      </div>

      <div ref={sectionRef} style={{ maxWidth: 900, margin: '0 auto', position: 'relative', zIndex: 1 }}>
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.8 }}
          style={{ textAlign: 'center', marginBottom: 72 }}
        >
          <p style={{ fontFamily: "'Jost', sans-serif", fontSize: '10px', letterSpacing: '0.35em', color: '#c9a96e', textTransform: 'uppercase', marginBottom: 16 }}>
            What Guests Say
          </p>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 'clamp(40px,6vw,72px)', fontWeight: 300, color: '#f5ead8' }}>
            Voices
          </h2>
          <div style={{ width: 40, height: 1, background: '#c9a96e', margin: '24px auto 0' }} />
        </motion.div>

        {/* Carousel */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={inView ? { opacity: 1 } : {}}
          transition={{ delay: 0.3 }}
          onMouseEnter={() => setPaused(true)}
          onMouseLeave={() => setPaused(false)}
          onTouchStart={(e) => {
            setPaused(true);
            setTouchStartX(e.touches[0].clientX);
          }}
          onTouchEnd={(e) => {
            onTouchEnd(e.changedTouches[0].clientX);
            setPaused(false);
          }}
          style={{ position: 'relative', minHeight: 360 }}
        >
          <AnimatePresence mode="wait" custom={direction}>
            <motion.div
              key={current}
              custom={direction}
              variants={trackVariants}
              initial="enter"
              animate="center"
              exit="exit"
              transition={{ duration: 0.55, ease: [0.22, 1, 0.36, 1] }}
              drag="x"
              dragConstraints={{ left: 0, right: 0 }}
              dragElastic={0.12}
              onDragStart={() => setPaused(true)}
              onDragEnd={(_, info) => {
                if (info.offset.x < -50) next();
                if (info.offset.x > 50) prev();
                setPaused(false);
              }}
              style={{
                display: 'grid',
                gridTemplateColumns: `repeat(${cardsPerView}, minmax(0, 1fr))`,
                gap: 20,
              }}
            >
              {visibleReviews.map((review, index) => {
                const isActive = index === 0;

                return (
                  <motion.article
                    key={review.id}
                    variants={cardVariants}
                    initial="hidden"
                    animate="visible"
                    style={{
                      background: isActive ? 'rgba(255,255,255,0.04)' : 'rgba(255,255,255,0.02)',
                      border: isActive
                        ? '1px solid rgba(201,169,110,0.35)'
                        : '1px solid rgba(201,169,110,0.14)',
                      padding: '32px 24px',
                      minHeight: 300,
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'space-between',
                      transform: isActive ? 'scale(1.015)' : 'scale(1)',
                      transition: 'transform 0.35s ease, border-color 0.35s ease, background 0.35s ease',
                    }}
                  >
                    <div>
                      <StarRating count={review.rating} />
                      <blockquote style={{
                        fontFamily: "'Cormorant Garamond', serif",
                        fontSize: 'clamp(18px,2vw,24px)',
                        fontWeight: 300,
                        fontStyle: 'italic',
                        color: '#e8d5b7',
                        lineHeight: 1.65,
                        letterSpacing: '0.01em',
                      }}>
                        "{review.comment}"
                      </blockquote>
                    </div>

                    <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginTop: 28 }}>
                      <img
                        src={review.avatar}
                        alt={review.name}
                        loading="lazy"
                        style={{
                          width: 48,
                          height: 48,
                          borderRadius: '50%',
                          objectFit: 'cover',
                          border: '1px solid rgba(201,169,110,0.3)',
                        }}
                      />
                      <div>
                        <div style={{
                          fontFamily: "'Jost', sans-serif",
                          fontSize: '12px',
                          fontWeight: 400,
                          color: '#f5ead8',
                          letterSpacing: '0.08em',
                        }}>
                          {review.name}
                        </div>
                        <div style={{
                          fontFamily: "'Jost', sans-serif",
                          fontSize: '9px',
                          color: 'rgba(201,169,110,0.62)',
                          letterSpacing: '0.16em',
                          textTransform: 'uppercase',
                          marginTop: 4,
                        }}>
                          Google Review
                        </div>
                      </div>
                    </div>
                  </motion.article>
                );
              })}
            </motion.div>
          </AnimatePresence>
        </motion.div>

        {/* Navigation */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 32, marginTop: 56 }}>
          <button
            onClick={prev}
            style={{ background: 'none', border: '1px solid rgba(201,169,110,0.3)', padding: '12px 16px', cursor: 'none', color: '#c9a96e', transition: 'all 0.3s' }}
            onMouseEnter={e => e.currentTarget.style.borderColor = '#c9a96e'}
            onMouseLeave={e => e.currentTarget.style.borderColor = 'rgba(201,169,110,0.3)'}
            aria-label="Previous"
          >
            <svg width="16" height="12" viewBox="0 0 16 12" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M6 1L1 6M1 6L6 11M1 6H15" />
            </svg>
          </button>

          <div style={{ display: 'flex', gap: 8 }}>
            {REVIEWS.map((_, i) => (
              <button
                key={i}
                onClick={() => goTo(i, i > current ? 1 : -1)}
                style={{
                  width: i === current ? 28 : 8,
                  height: 2,
                  background: i === current ? '#c9a96e' : 'rgba(201,169,110,0.25)',
                  border: 'none',
                  padding: 0,
                  cursor: 'none',
                  transition: 'all 0.3s',
                }}
                aria-label={`Go to review ${i + 1}`}
              />
            ))}
          </div>

          <button
            onClick={next}
            style={{ background: 'none', border: '1px solid rgba(201,169,110,0.3)', padding: '12px 16px', cursor: 'none', color: '#c9a96e', transition: 'all 0.3s' }}
            onMouseEnter={e => e.currentTarget.style.borderColor = '#c9a96e'}
            onMouseLeave={e => e.currentTarget.style.borderColor = 'rgba(201,169,110,0.3)'}
            aria-label="Next"
          >
            <svg width="16" height="12" viewBox="0 0 16 12" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M10 1L15 6M15 6L10 11M15 6H1" />
            </svg>
          </button>
        </div>

        <style>{`
          @media (max-width: 767px) {
            #testimonials blockquote {
              font-size: 20px !important;
            }
          }
        `}</style>
      </div>
    </section>
  );
}
